/// ------------------------------------------------------------------------- */
/// /* Enumerations                                                              */
/// /* -------------------------------------------------------------------------
abstract class photo_status_t {
  static const int PHOTO_STATUS_OK = 0;
  static const int PHOTO_STATUS_INVALID_ARG = 1;
  static const int PHOTO_STATUS_NOT_FOUND = 2;
  static const int PHOTO_STATUS_IO_ERROR = 3;
  static const int PHOTO_STATUS_DECODE_ERROR = 4;
  static const int PHOTO_STATUS_OUT_OF_MEMORY = 5;
  static const int PHOTO_STATUS_CANCELLED = 6;
  static const int PHOTO_STATUS_UNSUPPORTED = 7;
  static const int PHOTO_STATUS_BUSY = 8;
  static const int PHOTO_STATUS_INTERNAL = 9;
  static const int PHOTO_STATUS_BAD_STATE = 10;
}

abstract class photo_stage_t {
  static const int PHOTO_STAGE_PLACEHOLDER32 = 1;
  static const int PHOTO_STAGE_THUMB256 = 2;
  static const int PHOTO_STAGE_FULL = 3;
}

abstract class photo_priority_t {
  /// on-screen, must satisfy in this frame
  static const int PHOTO_PRIORITY_INTERACTIVE = 0;

  /// in current viewport / short prefetch
  static const int PHOTO_PRIORITY_VIEWPORT = 1;

  /// background; pre-cache and recache
  static const int PHOTO_PRIORITY_IDLE = 2;
}

abstract class photo_event_kind_t {
  static const int PHOTO_EVT_STAGE_READY = 1;
  static const int PHOTO_EVT_STAGE_FAILED = 2;

  /// aux64 = processed, aux64_b = total
  static const int PHOTO_EVT_IMPORT_PROGRESS = 3;

  /// Terminal import/rescan event. Carries the incremental-rescan summary:
  /// aux64        = added   (new assets inserted)
  /// aux64_b      = updated (existing assets whose file changed)
  /// _reserved[0] = skipped (unchanged files — size+mtime matched, not re-read)
  /// _reserved[1] = removed (rescan-pruned assets whose file is gone)
  static const int PHOTO_EVT_IMPORT_COMPLETE = 4;
  static const int PHOTO_EVT_SCAN_PROGRESS = 5;
  static const int PHOTO_EVT_CLUSTER_UPDATED = 6;

  /// 7 reserved — was PROVIDER_PROBED (removed; never emitted)
  static const int PHOTO_EVT_LOG = 8;

  /// Async catalog maintenance (compaction) finished. status is the result.
  static const int PHOTO_EVT_MAINTENANCE_COMPLETE = 9;

  /// One semantic-embedding job finished (Stage 9). asset_id = the asset;
  /// aux64 = 1 (one asset processed); status = per-item result
  /// (OK / UNSUPPORTED=skipped / DECODE_ERROR=failed). The Dart indexing
  /// controller counts these to drive progress, like SCAN_PROGRESS for faces.
  static const int PHOTO_EVT_EMBED_PROGRESS = 10;

  /// Async edit export / layered-save finished. status is the result;
  /// request_id matches the photo_asset_export / photo_asset_save_layered id.
  /// (11, not 10: Stage 9 landed EMBED_PROGRESS=10 on main first.)
  static const int PHOTO_EVT_EXPORT_COMPLETE = 11;
}

abstract class photo_log_level_t {
  static const int PHOTO_LOG_TRACE = 0;
  static const int PHOTO_LOG_DEBUG = 1;
  static const int PHOTO_LOG_INFO = 2;
  static const int PHOTO_LOG_WARN = 3;
  static const int PHOTO_LOG_ERROR = 4;
}

/// Engine configuration. Caller fills this and passes to photo_engine_create.
/// The engine copies what it needs; pointers do not need to outlive the call.
///
/// Zero/NULL fields request engine defaults:
/// memory_budget_bytes = 256 MiB
/// disk_budget_bytes   = 16 GiB
