  external ffi.Pointer<ffi.Char> catalog_path_utf8;

  /// LMDB env directory; will be created
  external ffi.Pointer<ffi.Char> cache_path_utf8;

  /// dir for ML models (M6+); may be NULL
  external ffi.Pointer<ffi.Char> models_path_utf8;

  /// memory LRU cap
  @ffi.Uint64()
  external int memory_budget_bytes;

  /// LMDB high-water mark for eviction
  @ffi.Uint64()
  external int disk_budget_bytes;

  @ffi.Uint32()
  external int decode_threads;

  @ffi.Uint32()
  external int io_threads;

  @ffi.Uint32()
  external int ml_threads;

  /// photo_log_level_t
  @ffi.Uint32()
  external int log_level;

  /// reserved; pass 0
  @ffi.Uint32()
  external int flags;
}

