  external int face_count;

  @ffi.Int32()
  external int confirmed_count;

  /// 0/1
  @ffi.Int32()
  external int confirmed;

  @ffi.Int32()
  external int _pad;

  @ffi.Array.multi([128])
  external ffi.Array<ffi.Char> name;
}

/// One face row: detection metadata + cluster/person links.
final class photo_face_t extends ffi.Struct {
  @ffi.Uint64()
  external int face_id;

  @ffi.Uint64()
  external int asset_id;

  /// -1 = unassigned
  @ffi.Int64()
  external int cluster_id;

  /// -1 = unconfirmed
  @ffi.Int64()
  external int person_id;

  /// source-image pixels
  @ffi.Float()
  external double box_x;

  @ffi.Float()
  external double box_y;

  @ffi.Float()
  external double box_w;

  @ffi.Float()
  external double box_h;

  @ffi.Float()
  external double det_score;

  @ffi.Float()
  external double quality;

  /// 0 = suggestion, 1 = user-confirmed
  @ffi.Int32()
  external int confirmed;

  /// 0/1 — user hid this detection
  @ffi.Int32()
  external int ignored;

  /// 0/1 — user-drawn rectangle (no embedding)
  @ffi.Int32()
  external int manual;

  @ffi.Int32()
  external int _pad;
}

/// Embedding progress counts for the indexing UI. `total` is all non-hidden
/// assets; `pending` includes assets with no row yet.
final class photo_embed_counts_t extends ffi.Struct {
  @ffi.Int64()
  external int done;

  @ffi.Int64()
  external int pending;

  @ffi.Int64()
  external int processing;

  @ffi.Int64()
  external int failed;

  @ffi.Int64()
  external int skipped;

  @ffi.Int64()
  external int total;
}

/// (asset_id, dominant colour 0xRRGGBB) for every embedded asset — drives colour
/// search. Fills up to `cap`, returns the TOTAL available (grow + re-call).
final class photo_asset_color_t extends ffi.Struct {
  @ffi.Uint64()
  external int asset_id;

  /// 0xRRGGBB
  @ffi.Int32()
  external int rgb;

  @ffi.Int32()
  external int _pad;
}

/// One ranked search result.
final class photo_search_hit_t extends ffi.Struct {
  @ffi.Uint64()
  external int asset_id;

  /// cosine similarity in [-1, 1]
  @ffi.Float()
  external double score;

  @ffi.Float()
  external double _pad;
}

/// Saved searches (saved_search table). query_json is opaque UTF-8.
final class photo_saved_search_t extends ffi.Struct {
  @ffi.Uint64()
  external int id;

  /// ns since epoch
  @ffi.Int64()
  external int created;

  @ffi.Array.multi([128])
  external ffi.Array<ffi.Char> name;
}

